#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int P[N], Q[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &P[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &Q[i]);
        }
        // Generate all permutations of P
        int permutations[N][N];
        memcpy(permutations[0], P, sizeof(P));
        int count = 1;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < K; j++) {
                int temp = permutations[i][N - K + j];
                for (int k = N - K + j; k > j; k--) {
                    permutations[count][k] = permutations[i][k - 1];
                }
                permutations[count][j] = temp;
                count++;
            }
        }
        // Find the lexicographical index of Q
        int index = -1;
        for (int i = 0; i < count; i++) {
            if (memcmp(permutations[i], Q, sizeof(Q)) == 0) {
                index = i + 1;
                break;
            }
        }
        printf("%d\n", index);
    }
    return 0;
}

