            for (int i = 0; i < N; i++) {
                Q[i] = sc.nextInt();
            }
            // Generate all permutations of P
            int[][] permutations = new int[N][N];
            System.arraycopy(P, 0, permutations[0], 0, N);
            int count = 1;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < K; j++) {
                    int temp = permutations[i][N - K + j];
                    for (int k = N - K + j; k > j; k--) {
                        permutations[count][k] = permutations[i][k - 1];
                    }
                    permutations[count][j] = temp;
                    count++;
                }
            }
            // Find the lexicographical index of Q
            int index = -1;
            for (int i = 0; i < count; i++) {
                if (Arrays.equals(permutations[i], Q)) {
                    index = i + 1;
                    break;
                }
            }
            System.out.println(index);
