let idx = 0;

function nextLine() {
    return input[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextIntArray() {
    return nextLine().split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let [N, K] = nextIntArray();
    let P = nextIntArray();
    let Q = nextIntArray();
    // Generate all permutations of P
    let permutations = [P.slice()];
    let count = 1;
    for (let i = 0; i < N; i++) {
        for (let j = 0; j < K; j++) {
            let temp = permutations[i][N - K + j];
            for (let k = N - K + j; k > j; k--) {
                permutations[count][k] = permutations[i][k - 1];
            }
            permutations[count][j] = temp;
            count++;
            permutations.push(permutations[count - 1].slice());
        }
    }
    // Find the lexicographical index of Q
    let index = -1;
    for (let i = 0; i < count; i++) {
        if (permutations[i].every((val, idx) => val === Q[idx])) {
            index = i + 1;
            break;
        }
    }
